class UnionFind:
    def __init__(self, n):
        self.parent = list(range(n))
        self.rank = [0] * n

    def find(self, i):
        if self.parent[i] == i:
            return i
        self.parent[i] = self.find(self.parent[i])
        return self.parent[i]

    def union(self, i, j):
        root_i = self.find(i)
        root_j = self.find(j)

        if root_i != root_j:
            if self.rank[root_i] < self.rank[root_j]:
                self.parent[root_i] = root_j
            elif self.rank[root_i] > self.rank[root_j]:
                self.parent[root_j] = root_i
            else:
                self.parent[root_j] = root_i
                self.rank[root_i] += 1
            return True
        return False


def validTree(n: int, edges: list[list[int]]) -> bool:
    # Bir ağaç, n düğüm ve tam olarak n-1 kenardan oluşmalıdır.
    # Eğer kenar sayısı n-1'den farklıysa, ağaç olamaz.
    # (n-1'den azsa bağlantısızdır, n-1'den çoksa döngü içerir.)
    if len(edges) != n - 1:
        return False

    uf = UnionFind(n)

    # Union-Find kullanarak döngü kontrolü yap.
    for u, v in edges:
        # Eğer uf.union(u, v) False dönerse, bu u ve v'nin zaten aynı kümede olduğu anlamına gelir.
        # Bu durumda, (u, v) kenarını eklemek bir döngü oluşturur.
        if not uf.union(u, v):
            return False

    # Tüm n-1 kenar döngü oluşturmadan başarılı bir şekilde birleştirildiyse,
    # grafik bağlı ve döngüsüzdür, dolayısıyla geçerli bir ağaçtır.
    return True
